import java.io.File;
import java.io.IOException;

/**
 * Configuration service for loading and validating XML configuration files.
 * This service validates XML files before parsing them into DOM objects.
 */
public class ConfigService {

    /**
     * Loads and validates an XML configuration file.
     * 
     * @param configPath the path to the XML configuration file
     * @return the parsed Document object after successful validation
     * @throws IllegalArgumentException if configPath is null or empty
     * @throws IOException if the file cannot be read
     * @throws SAXException if the XML is not well-formed or validation fails
     * @throws ParserConfigurationException if a DocumentBuilder cannot be created
     */
    public Document loadConfig(String configPath) 
            throws IOException, SAXException, ParserConfigurationException {

        // Validate input parameters
        if (configPath == null || configPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Config path cannot be null or empty");
        }

        File configFile = new File(configPath);

        // Check if file exists
        if (!configFile.exists()) {
            throw new IOException("Configuration file not found: " + configPath);
        }

        // Check if it's a file (not a directory)
        if (!configFile.isFile()) {
            throw new IOException("Path does not point to a file: " + configPath);
        }

        // Step 1: Validate the XML file for well-formedness
        validateXml(configFile);

        // Step 2: Parse the validated XML file into a Document object
        return parseXml(configFile);
    }

