     * 
     * @param xmlFile the XML file to validate
     * @throws SAXException if the XML is not well-formed
     * @throws IOException if the file cannot be read
     */
    private void validateXml(File xmlFile) throws SAXException, IOException {
        // Create SchemaFactory for XML Schema
        SchemaFactory schemaFactory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);

        // Create a Schema that validates well-formedness without requiring a specific schema
        // Using a relaxed schema approach for well-formedness checking
        Schema schema = schemaFactory.newSchema();

        // Create Validator from the Schema
        Validator validator = schema.newValidator();

        // Validate the XML file
        validator.validate(new StreamSource(xmlFile));
    }

    /**
     * Parses the XML file into a DOM Document object.
     * 
     * @param xmlFile the XML file to parse
     * @return the parsed Document object
     * @throws ParserConfigurationException if a DocumentBuilder cannot be created
     * @throws SAXException if parsing fails
     * @throws IOException if the file cannot be read
     */
    private Document parseXml(File xmlFile) 
            throws ParserConfigurationException, SAXException, IOException {

        // Create DocumentBuilderFactory
        DocumentBuilderFactory documentBuilderFactory = DocumentBuilderFactory.newInstance();

        // Configure factory for security and standards compliance
        documentBuilderFactory.setNamespaceAware(true);
        documentBuilderFactory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // Disable external entities to prevent XXE attacks
        documentBuilderFactory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        documentBuilderFactory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        documentBuilderFactory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        documentBuilderFactory.setXIncludeAware(false);
        documentBuilderFactory.setExpandEntityReferences(false);

        // Create DocumentBuilder
        DocumentBuilder documentBuilder = documentBuilderFactory.newDocumentBuilder();

        // Parse and return the Document
        return documentBuilder.parse(xmlFile);
    }
}

